BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?doc ?docName ?name WHERE {
  ?doc rdf:type vocab:document .
  ?doc vocab:NamedElement_name ?docName .
  OPTIONAL { 
    ?doc vocab:Element_ownedElement ?elem .
    ?elem vocab:NamedElement_name ?name .
    FILTER(CONTAINS(LCASE(STR(?name)), LCASE("DOORS")))
  }
}
LIMIT 50

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?pkg ?pkgName ?doc ?docName WHERE {
  ?pkg vocab:NamedElement_name "TMT%20Requirements%20imported%20from%20DOORS" .
  ?pkg rdf:type vocab:package .
  OPTIONAL {
    ?pkg vocab:Element_ownedElement ?doc .
    ?doc rdf:type vocab:document .
    ?doc vocab:NamedElement_name ?docName .
  }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?doc ?docName ?view ?viewName WHERE {
  ?doc rdf:type vocab:document .
  ?doc vocab:NamedElement_name ?docName .
  FILTER(CONTAINS(LCASE(STR(?docName)), LCASE("APS")))
  OPTIONAL {
    ?doc vocab:Element_ownedElement ?view .
    ?view vocab:NamedElement_name ?viewName .
  }
}
LIMIT 50

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?model ?modelName ?elem ?elemName ?type WHERE {
  ?model vocab:NamedElement_name "DOORS%20Requirements%20Data%20Base%20(L0%20through%20L2)" .
  ?model rdf:type vocab:model .
  OPTIONAL {
    ?model vocab:Element_ownedElement ?elem .
    ?elem vocab:NamedElement_name ?elemName .
    ?elem rdf:type ?type .
  }
}
LIMIT 50
